def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.log1p(cap) * 30
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.exp(usage * 0.15)
            if cap > 15:
                base_priority += 80 * np.sqrt(cap) + 50 * np.sin(cap * 1.8)
            else:
                base_priority -= 60 * usage ** 1.2
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.cos(usage * np.pi * i * 0.7) * 18 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 300 * (1 - delta ** 0.4)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.5)) * 22 / j
            if int(cap * 4) % 5 == 1:
                base_priority += 55 * np.tan(cap / 20)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**1.7
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 6 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.sin(cap * 2.7)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2)**2.5
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 4)
                    if m == 14 and usage > 2.7:
                        fluctuation += 25
            if cap % 2.7 < 0.4:
                base_priority += 40 * np.cos(cap * 4)
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 2.8
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 18 / n
                    if n % 4 == 3:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 13 / (n + 3)
                    if n == 15 and usage > 1.8:
                        fluctuation += 20
            if cap % 1.8 < 0.5:
                base_priority += 33 * np.cos(cap * 3)
        elif 0.4 < usage <= 1:
            base_priority += 120 * (1 - usage)**1.5
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.2) * 14 / o
                if usage < 0.05 * o:
                    fluctuation -= 7 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 320
            elif cap < 1.2:
                base_priority += np.log1p(cap * 25) * 42
            else:
                base_priority += (cap % 7) * 24
        else:
            base_priority += 260 * (1 - usage) ** 3
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 14 / p
                if usage < 0.01 * p:
                    fluctuation -= 15 * p
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 33
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 22)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) == 1:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.15:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 100
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 2700) % 21 == 0:
            proximity += 18
        if int(cap * 1000) % 25 == 0:
            proximity -= 13
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.015:
                proximity += 25 / u
            elif diff < 0.04:
                proximity += 14 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_chk = int(cap * 1800) % (v + 11)
            if mod_chk == 0:
                proximity += v * 6
            elif mod_chk == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1800) % (w + 8)
            if mod_chk == 0:
                proximity += 12 * w
            elif mod_chk == 4:
                proximity -= 9 * w
        priority += proximity
        if usage < 0.004:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1.2 < 0.07:
                priority += 50
            if (int(cap * 3000) % 27 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 720) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
